```cpp
#pragma once

#include <reaction/core/observer_node.h>
#include <reaction/graph/observer_graph.h>
#include <reaction/concurrency/thread_manager.h>
#include <memory>
#include <string>

namespace test_reaction {

// ============================================
// 数据模型定义
// ============================================

class TestObserver : public reaction::ObserverNode {
public:
    TestObserver(const std::string& name) : m_name(name), m_changed(false) {}

    void valueChanged(bool changed = true) override {
        m_changed = changed;
        m_callCount++;
        // Call base class to propagate notification to observers
        ObserverNode::valueChanged(changed);
    }

    bool wasChanged() const { return m_changed; }
    int getCallCount() const { return m_callCount; }
    const std::string& getName() const { return m_name; }

private:
    std::string m_name;
    bool m_changed;
    int m_callCount = 0;
};

// ============================================
// 函数实现
// ============================================

/**
 * Function: Create observer relationship and test notification
 *
 * @param observerName Name for the observer node
 * @param targetName Name for the target node
 * @return std::pair<bool, int> Pair of whether observer was notified and call count
 */
std::pair<bool, int> test_observer_notification(const std::string& observerName, const std::string& targetName) {
    // 1. Create observer node with observerName
    auto observer = std::make_shared<TestObserver>(observerName);

    // 2. Create target node with targetName
    auto target = std::make_shared<TestObserver>(targetName);

    // 3. Get the global ObserverGraph instance
    auto observerGraph = reaction::ObserverGraph::getInstance();

    // 4. Add observer relationship where observer observes target
    observerGraph.addObserver(observer, target);

    // 5. Notify the target of a change using valueChanged
    target->valueChanged(true);

    // 6. Check if observer was notified by checking its state
    bool wasNotified = observer->wasChanged();

    // 7. Get the call count from the observer
    int callCount = observer->getCallCount();

    // 8. Return pair containing notification status and call count
    return std::make_pair(wasNotified, callCount);
}

}  // namespace test_reaction
```

## Key Implementation Points:

1. **Observer and Target Creation**: Used `std::make_shared<TestObserver>()` to create both observer and target nodes with the provided names.

2. **ObserverGraph Singleton**: Retrieved the singleton instance using `reaction::ObserverGraph::getInstance()`.

3. **Observer Relationship**: Added the observer relationship using `observerGraph.addObserver(observer, target)`, where the first parameter is the observing node and the second is the node being observed.

4. **Notification**: Called `valueChanged(true)` on the target node to trigger the notification chain.

5. **State Checking**: Used the `wasChanged()` method to verify if the observer received the notification.

6. **Call Count**: Retrieved the call count using `getCallCount()` to track how many times the observer was notified.

7. **Return Value**: Returned a `std::pair<bool, int>` containing the notification status and call count as specified.

This implementation follows all the assessment objectives and correctly utilizes the reaction library's observer pattern functionality.

