/**
 * Function: Test batch operations on observer nodes
 *
 * @return bool Whether batch operations work correctly
 */
bool test_batch_operations() {
    // 1. Create observer nodes using reaction::ObserverNode::create
    auto node1 = reaction::ObserverNode::create();
    auto node2 = reaction::ObserverNode::create();

    // 2. Get observer graph instance using reaction::ObserverGraph::getInstance
    auto& observerGraph = reaction::ObserverGraph::getInstance();

    // 3. Create batch ID using std::make_unique
    auto batchId = std::make_unique<void>(0);

    // 4. Register nodes to batch using ObserverGraph::getInstance().registerActiveBatch
    // Collect nodes into a NodeSet
    reaction::NodeSet nodesToRegister;
    nodesToRegister.insert(node1);
    nodesToRegister.insert(node2);

    observerGraph.registerActiveBatch(batchId.get(), nodesToRegister);

    // 5. Verify nodes are in batch using ObserverNode::isInActiveBatch
    bool test1 = node1->isInActiveBatch();
    bool test2 = node2->isInActiveBatch();

    // Verify both nodes are in active batch
    if (!test1 || !test2) {
        return false;
    }

    // 6. Unregister batch using ObserverGraph::getInstance().unregisterActiveBatch
    observerGraph.unregisterActiveBatch(batchId.get());

    // 7. Verify nodes are no longer in batch using ObserverNode::isInActiveBatch
    bool test3 = node1->isInActiveBatch();
    bool test4 = node2->isInActiveBatch();

    // Verify both nodes are no longer in active batch
    if (test3 || test4) {
        return false;
    }

    // 8. Return success status
    return true;
}

}  // namespace test_reaction
```

