    // 3. Use addNode() to add all three observers to the graph
    graph.addNode(target);
    graph.addNode(observer1);
    graph.addNode(observer2);

    // 4. Set up the chain: observer2 observes observer1, observer1 observes target
    graph.addObserver(observer2, observer1);  // observer2 depends on observer1
    graph.addObserver(observer1, target);    // observer1 depends on target

