    using namespace reaction;

    // 1. Create a reactive variable for the sensor using reaction::var with initial value
    auto sensor = var(initialValue);

    // 2. Create two reactive variables to track recompute count and last processed value using reaction::var
    auto recomputeCount = var(0);
    auto lastProcessedValue = var(initialValue);

    // 3. Create a filter-triggered calculation using reaction::calc that:
    //    - Takes the sensor value and previous value as inputs
    //    - Calculates the difference between current and previous values
    //    - Applies a filter to only trigger when the absolute difference exceeds the threshold
    //    - Updates the last processed value and increments the recompute count on each trigger

    auto statusCalc = calc([&]() -> std::string {
        double current = sensor();
        double previous = lastProcessedValue();

        // Calculate absolute difference
        double diff = std::abs(current - previous);

        // Determine status based on levelThreshold
        std::string status = (current > levelThreshold) ? "HIGH" : "NORMAL";

        // Update last processed value
        lastProcessedValue.value(current);

        // Increment recompute count
        recomputeCount.value(recomputeCount() + 1);

        return status;
    });

    // 4. Apply the filter to the calculation using the filter method
    statusCalc.filter([&](const std::string& status) -> bool {
        double current = sensor();
        double previous = lastProcessedValue();
        double diff = std::abs(current - previous);
        return diff > diffThreshold;
    });

    // 5. Update the sensor with the first value using the value method
    sensor.value(firstUpdate);

    // 6. Record the recompute count after the first update
    int firstCount = recomputeCount();

    // 7. Update the sensor with the second value using the value method
    sensor.value(secondUpdate);

    // 8. Record the recompute count after the second update
    int secondCount = recomputeCount();

    // 9. Get the final status string from the calculation
    std::string finalStatus = statusCalc();

    // 10. Return a tuple containing the final status, first recompute count, and second recompute count
    return std::make_tuple(finalStatus, firstCount, secondCount);
}

