private:
    std::string m_name;
};

struct ObserverCollectionSummary {
    std::size_t totalObservers;
    bool containsDirectObserver;
    bool containsTransitiveObserver;
};

ObserverCollectionSummary test_observer_collection() {
    // 1. Create NamedObserverNode instances
    NamedObserverNode source("source_node");
    NamedObserverNode direct("direct_observer");
    NamedObserverNode transitive("transitive_observer");

    // 2. Get observer graph instance
    auto& observerGraph = reaction::ObserverGraph::getInstance();

    // 3. Register nodes
    observerGraph.addNode(source.getId());
    observerGraph.addNode(direct.getId());
    observerGraph.addNode(transitive.getId());

    // 4. Set up direct observer relationship
    observerGraph.addObserver(source.getId(), direct.getId());

    // 5. Set up transitive observer relationship
    observerGraph.addObserver(direct.getId(), transitive.getId());

    // 6. Create NodeSet to store collected observers
    reaction::NodeSet collectedObservers;

    // 7. Collect observers
    observerGraph.collectObservers(source.getId(), collectedObservers);

    // 8. Check if direct observer is in collected set
    bool containsDirect = false;
    for (const auto& observerWeak : collectedObservers) {
        if (auto observer = observerWeak.lock()) {
            if (observer == direct.getPtr()) {
                containsDirect = true;
                break;
            }
        }
    }

    // 9. Check if transitive observer is in collected set
    bool containsTransitive = false;
    for (const auto& observerWeak : collectedObservers) {
        if (auto observer = observerWeak.lock()) {
            if (observer == transitive.getPtr()) {
                containsTransitive = true;
                break;
            }
        }
    }

    // 10. Return collection summary
    return ObserverCollectionSummary{
        .totalObservers = collectedObservers.size(),
        .containsDirectObserver = containsDirect,
        .containsTransitiveObserver = containsTransitive
    };
}

}  // namespace test_reaction
